"use client";

export default function AddToCart({ item, cart, handleCart }: any) {
  const isAdded = cart.some((i: any) => i.id === item.id);

  return (
    <button
      onClick={() => handleCart(item)}
      style={{
        background: isAdded ? "red" : "green",
        color: "white",
        padding: "6px",
        border: "none",
        cursor: "pointer",
      }}
    >
      {isAdded ? "Remove ❌" : "Add to Cart 🛒"}
    </button>
  );
}